#include <stdio.h>
#include <string.h>

int isPalindrome(char *s, int i, int j) {
    while (i < j) {
        if (s[i] != s[j]) return 0;
        i++, j--;
    }
    return 1;
}

int minSubstrings(char *s, int n) {
    int dp[n][n], dp2[n];
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            dp[i][j] = 0;
        }
    }
    for (int i = 0; i < n; i++) {
        dp2[i] = n;
    }
    for (int i = 0; i < n; i++) {
        for (int j = i; j < n; j++) {
            if (isPalindrome(s, i, j)) {
                dp[i][j] = 1;
            }
        }
    }
    dp2[0] = 1;
    for (int i = 1; i < n; i++) {
        for (int j = 0; j <= i; j++) {
            if (dp[j][i]) {
                if (j == 0) {
                    dp2[i] = 1;
                } else {
                    dp2[i] = (dp2[i] < dp2[j - 1] + 1) ? dp2[i] : dp2[j - 1] + 1;
                }
            }
        }
    }
    return dp2[n - 1];
}

int main() {
    int t;
    scanf("%d", &t);
    while (t--) {
        int n;
        scanf("%d", &n);
        char s[n + 1];
        scanf("%s", s);
        printf("%d\n", minSubstrings(s, n));
    }
    return 0;
}

