def is_palindrome(s, i, j):
    while i < j:
        if s[i] != s[j]:
            return 0
        i += 1
        j -= 1
    return 1

def min_substrings(s):
    n = len(s)
    dp = [[0] * n for _ in range(n)]
    dp2 = [n] * n
    for i in range(n):
        for j in range(i, n):
            if is_palindrome(s, i, j):
                dp[i][j] = 1
    dp2[0] = 1
    for i in range(1, n):
        for j in range(i + 1):
            if dp[j][i]:
                if j == 0:
                    dp2[i] = 1
                else:
                    dp2[i] = min(dp2[i], dp2[j - 1] + 1)
    return dp2[-1]

